module top_module(
    input clk,
    input [7:0] data_in1,
    input [7:0] data_in2,
    output reg [7:0] q_out
);reg [7:0] obf_shift_reg [0:7];

always @(posedge clk) begin
    obf_shift_reg[0] <= data_in1;
    obf_shift_reg[1] <= obf_shift_reg[0];
    obf_shift_reg[2] <= obf_shift_reg[1];
    obf_shift_reg[3] <= obf_shift_reg[2];
    obf_shift_reg[4] <= obf_shift_reg[3];
    obf_shift_reg[5] <= obf_shift_reg[4];
    obf_shift_reg[6] <= obf_shift_reg[5];
    obf_shift_reg[7] <= data_in2;
end

assign q_out = obf_shift_reg[7];

endmodule
